 30→// SqliteArchiveConfig holds the configuration for the SQLite archive backend.
 31→type SqliteArchiveConfig struct {
 32→	DBPath string `json:"db-path"` // Path to SQLite database file
 33→}
 34→
 35→// SqliteArchive implements ArchiveBackend using a SQLite database with BLOB storage.
 36→// Job metadata and data are stored as JSON BLOBs with indexes for fast queries.
 37→//
 38→// Uses WAL (Write-Ahead Logging) mode for better concurrency and a 64MB cache.
 39→type SqliteArchive struct {
 40→	db       *sql.DB  // SQLite database connection
 41→	clusters []string // List of discovered cluster names
 42→}
 43→
 44→// sqliteSchema defines the database schema for SQLite archive backend.
 45→// Jobs table: stores job metadata and data as BLOBs with compression flag
 46→// Clusters table: stores cluster configurations
 47→// Metadata table: stores version and other key-value pairs
 48→const sqliteSchema = `
 49→CREATE TABLE IF NOT EXISTS jobs (
 50→    id INTEGER PRIMARY KEY AUTOINCREMENT,
 51→    job_id INTEGER NOT NULL,
 52→    cluster TEXT NOT NULL,
 53→    start_time INTEGER NOT NULL,
 54→    meta_json BLOB NOT NULL,
 55→    data_json BLOB,
 56→    data_compressed BOOLEAN DEFAULT 0,
 57→    created_at INTEGER NOT NULL,
 58→    updated_at INTEGER NOT NULL,
 59→    UNIQUE(job_id, cluster, start_time)
 60→);
 61→
 62→CREATE INDEX IF NOT EXISTS idx_jobs_cluster ON jobs(cluster);
 63→CREATE INDEX IF NOT EXISTS idx_jobs_start_time ON jobs(start_time);
 64→CREATE INDEX IF NOT EXISTS idx_jobs_order ON jobs(cluster, start_time);
 65→CREATE INDEX IF NOT EXISTS idx_jobs_lookup ON jobs(cluster, job_id, start_time);
 66→
 67→CREATE TABLE IF NOT EXISTS clusters (
 68→    name TEXT PRIMARY KEY,
 69→    config_json BLOB NOT NULL,
 70→    updated_at INTEGER NOT NULL
 71→);
 72→
 73→CREATE TABLE IF NOT EXISTS metadata (
 74→    key TEXT PRIMARY KEY,
 75→    value TEXT NOT NULL
 76→);
 77→`
 78→
 79→func (sa *SqliteArchive) Init(rawConfig json.RawMessage) (uint64, error) {
 80→	var cfg SqliteArchiveConfig
 81→	if err := json.Unmarshal(rawConfig, &cfg); err != nil {
 82→		cclog.Warnf("SqliteArchive Init() > Unmarshal error: %#v", err)
 83→		return 0, err
 84→	}
 85→
 86→	if cfg.DBPath == "" {
 87→		err := fmt.Errorf("SqliteArchive Init(): empty database path")
 88→		cclog.Errorf("SqliteArchive Init() > config error: %v", err)
 89→		return 0, err
 90→	}
 91→
 92→	// Open SQLite database
 93→	db, err := sql.Open("sqlite3", cfg.DBPath)
 94→	if err != nil {
 95→		cclog.Errorf("SqliteArchive Init() > failed to open database: %v", err)
 96→		return 0, err
 97→	}
 98→	sa.db = db
 99→
100→	// Set pragmas for better performance
101→	pragmas := []string{
102→		"PRAGMA journal_mode=WAL",
103→		"PRAGMA synchronous=NORMAL",
104→		"PRAGMA cache_size=-64000", // 64MB cache
105→		"PRAGMA busy_timeout=5000",
106→	}
107→	for _, pragma := range pragmas {
108→		if _, err := sa.db.Exec(pragma); err != nil {
109→			cclog.Warnf("SqliteArchive Init() > pragma failed: %v", err)
110→		}
111→	}
112→
113→	// Create schema
114→	if _, err := sa.db.Exec(sqliteSchema); err != nil {
115→		cclog.Errorf("SqliteArchive Init() > schema creation failed: %v", err)
116→		return 0, err
117→	}
118→
119→	// Check/set version
120→	var versionStr string
121→	err = sa.db.QueryRow("SELECT value FROM metadata WHERE key = 'version'").Scan(&versionStr)
122→	if err == sql.ErrNoRows {
123→		// First time initialization, set version
124→		_, err = sa.db.Exec("INSERT INTO metadata (key, value) VALUES ('version', ?)", fmt.Sprintf("%d", Version))
125→		if err != nil {
126→			cclog.Errorf("SqliteArchive Init() > failed to set version: %v", err)
127→			return 0, err
128→		}
129→		versionStr = fmt.Sprintf("%d", Version)
130→	} else if err != nil {
131→		cclog.Errorf("SqliteArchive Init() > failed to read version: %v", err)
132→		return 0, err
133→	}
134→
135→	version, err := strconv.ParseUint(versionStr, 10, 64)
136→	if err != nil {
137→		cclog.Errorf("SqliteArchive Init() > version parse error: %v", err)
138→		return 0, err
139→	}
140→
141→	if version != Version {
142→		return version, fmt.Errorf("unsupported version %d, need %d", version, Version)
143→	}
144→
145→	// Discover clusters
146→	sa.clusters = []string{}
147→	rows, err := sa.db.Query("SELECT DISTINCT cluster FROM jobs ORDER BY cluster")
148→	if err != nil {
149→		cclog.Errorf("SqliteArchive Init() > failed to query clusters: %v", err)
150→		return 0, err
151→	}
152→	defer rows.Close()
153→
154→	for rows.Next() {
155→		var cluster string
156→		if err := rows.Scan(&cluster); err != nil {
157→			cclog.Errorf("SqliteArchive Init() > failed to scan cluster: %v", err)
158→			continue
159→		}
160→		sa.clusters = append(sa.clusters, cluster)
161→	}
162→
163→	cclog.Infof("SqliteArchive initialized with database '%s', found %d clusters", cfg.DBPath, len(sa.clusters))
164→	return version, nil
165→}
166→
167→func (sa *SqliteArchive) Info() {
168→	fmt.Printf("SQLite Job archive database\n")
169→
170→	ci := make(map[string]*clusterInfo)
171→
172→	rows, err := sa.db.Query(`
173→		SELECT cluster, COUNT(*), MIN(start_time), MAX(start_time),
174→		       SUM(LENGTH(meta_json) + COALESCE(LENGTH(data_json), 0))
175→		FROM jobs
176→		GROUP BY cluster
177→	`)
178→	if err != nil {
179→		cclog.Fatalf("SqliteArchive Info() > query failed: %s", err.Error())
180→	}
181→	defer rows.Close()
182→
183→	for rows.Next() {
184→		var cluster string
185→		var numJobs int
186→		var dateFirst, dateLast int64
187→		var diskSize int64
188→
189→		if err := rows.Scan(&cluster, &numJobs, &dateFirst, &dateLast, &diskSize); err != nil {
190→			cclog.Errorf("SqliteArchive Info() > scan failed: %v", err)
191→			continue
192→		}
193→
194→		ci[cluster] = &clusterInfo{
195→			numJobs:   numJobs,
196→			dateFirst: dateFirst,
197→			dateLast:  dateLast,
198→			diskSize:  float64(diskSize) / (1024 * 1024), // Convert to MB
199→		}
200→	}
201→
202→	cit := clusterInfo{dateFirst: time.Now().Unix()}
203→	w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', tabwriter.Debug)
204→	fmt.Fprintln(w, "cluster\t#jobs\tfrom\tto\tsize (MB)")
205→	for cluster, clusterInfo := range ci {
206→		fmt.Fprintf(w, "%s\t%d\t%s\t%s\t%.2f\n", cluster,
207→			clusterInfo.numJobs,
208→			time.Unix(clusterInfo.dateFirst, 0),
209→			time.Unix(clusterInfo.dateLast, 0),
210→			clusterInfo.diskSize)
211→
212→		cit.numJobs += clusterInfo.numJobs
213→		cit.dateFirst = util.Min(cit.dateFirst, clusterInfo.dateFirst)
214→		cit.dateLast = util.Max(cit.dateLast, clusterInfo.dateLast)
215→		cit.diskSize += clusterInfo.diskSize
216→	}
217→
218→	fmt.Fprintf(w, "TOTAL\t%d\t%s\t%s\t%.2f\n",
219→		cit.numJobs, time.Unix(cit.dateFirst, 0), time.Unix(cit.dateLast, 0), cit.diskSize)
220→	w.Flush()
221→}
