314→func (sa *SqliteArchive) LoadClusterCfg(name string) (*schema.Cluster, error) {
315→	var configBlob []byte
316→	err := sa.db.QueryRow("SELECT config_json FROM clusters WHERE name = ?", name).Scan(&configBlob)
317→	if err != nil {
