520→func (sa *SqliteArchive) CompressLast(starttime int64) int64 {
521→	var lastStr string
522→	err := sa.db.QueryRow("SELECT value FROM metadata WHERE key = 'compress_last'").Scan(&lastStr)
523→
524→	var last int64
525→	if err == sql.ErrNoRows {
526→		last = starttime
527→	} else if err != nil {
528→		cclog.Errorf("SqliteArchive CompressLast() > query error: %v", err)
529→		last = starttime
530→	} else {
531→		last, err = strconv.ParseInt(lastStr, 10, 64)
532→		if err != nil {
533→			cclog.Errorf("SqliteArchive CompressLast() > parse error: %v", err)
534→			last = starttime
535→		}
536→	}
537→
538→	cclog.Infof("SqliteArchive CompressLast() - start %d last %d", starttime, last)
539→
540→	// Update timestamp
541→	_, err = sa.db.Exec(`
542→		INSERT INTO metadata (key, value) VALUES ('compress_last', ?)
543→		ON CONFLICT(key) DO UPDATE SET value = excluded.value
544→	`, fmt.Sprintf("%d", starttime))
545→	if err != nil {
546→		cclog.Errorf("SqliteArchive CompressLast() > update error: %v", err)
547→	}
548→
549→	return last
