191→func (r *UserRepository) UpdateUser(dbUser *schema.User, user *schema.User) error {
192→	// user contains updated info -> Apply to dbUser
193→	// --- Simple Name Update ---
194→	if dbUser.Name != user.Name {
195→		if _, err := sq.Update("hpc_user").Set("name", user.Name).Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec(); err != nil {
196→			cclog.Errorf("error while updating name of user '%s'", user.Username)
197→			return err
198→		}
199→	}
200→
201→	// --- Def Helpers ---
202→	// Helper to update roles
203→	updateRoles := func(roles []string) error {
204→		rolesJSON, _ := json.Marshal(roles)
205→		_, err := sq.Update("hpc_user").Set("roles", rolesJSON).Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec()
206→		return err
207→	}
208→
209→	// Helper to update projects
210→	updateProjects := func(projects []string) error {
211→		projectsJSON, _ := json.Marshal(projects)
212→		_, err := sq.Update("hpc_user").Set("projects", projectsJSON).Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec()
213→		return err
214→	}
215→
216→	// Helper to clear projects
217→	clearProjects := func() error {
218→		_, err := sq.Update("hpc_user").Set("projects", "[]").Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec()
219→		return err
220→	}
221→
222→	// --- Manager Role Handling ---
223→	if dbUser.HasRole(schema.RoleManager) && user.HasRole(schema.RoleManager) && !reflect.DeepEqual(dbUser.Projects, user.Projects) {
224→		// Existing Manager: update projects
225→		if err := updateProjects(user.Projects); err != nil {
226→			return err
227→		}
228→	} else if dbUser.HasRole(schema.RoleUser) && user.HasRole(schema.RoleManager) && user.HasNotRoles([]schema.Role{schema.RoleAdmin}) {
229→		// New Manager: update roles and projects
230→		if err := updateRoles(user.Roles); err != nil {
231→			return err
232→		}
233→		if err := updateProjects(user.Projects); err != nil {
234→			return err
235→		}
236→	} else if dbUser.HasRole(schema.RoleManager) && user.HasNotRoles([]schema.Role{schema.RoleAdmin, schema.RoleManager}) {
237→		// Remove Manager: update roles and clear projects
238→		if err := updateRoles(user.Roles); err != nil {
239→			return err
240→		}
241→		if err := clearProjects(); err != nil {
242→			return err
243→		}
244→	}
245→
246→	// --- Support Role Handling ---
247→	if dbUser.HasRole(schema.RoleUser) && dbUser.HasNotRoles([]schema.Role{schema.RoleSupport}) &&
248→		user.HasRole(schema.RoleSupport) && user.HasNotRoles([]schema.Role{schema.RoleAdmin}) {
249→		// New Support: update roles
250→		if err := updateRoles(user.Roles); err != nil {
251→			return err
252→		}
253→	} else if dbUser.HasRole(schema.RoleSupport) && user.HasNotRoles([]schema.Role{schema.RoleAdmin, schema.RoleSupport}) {
254→		// Remove Support: update roles
255→		if err := updateRoles(user.Roles); err != nil {
256→			return err
257→		}
258→	}
259→
260→	return nil
261→}
